def init_db() -> None:
    with sqlite3.connect(DB_PATH) as conn:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS contributions (
                id TEXT PRIMARY KEY,
                created_at TEXT NOT NULL,
                kind TEXT NOT NULL,
                filename TEXT NOT NULL,
                label TEXT,
                metadata TEXT,
                path TEXT NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS training_runs (
                id TEXT PRIMARY KEY,
                started_at TEXT NOT NULL,
                finished_at TEXT,
                status TEXT NOT NULL,
                metrics TEXT,
                model_path TEXT,
                error TEXT
            )
            """
        )
        conn.commit()


def now_iso() -> str:
    return datetime.utcnow().isoformat() + "Z"


def save_upload_file(upload_file: UploadFile, destination: str) -> None:
    with open(destination, "wb") as buffer:
        shutil.copyfileobj(upload_file.file, buffer)


def allowed_image_filename(filename: str) -> bool:
    ext = os.path.splitext(filename.lower())[1]
    return ext in {".jpg", ".jpeg", ".png", ".bmp", ".webp"}


def allowed_csv_filename(filename: str) -> bool:
    return os.path.splitext(filename.lower())[1] == ".csv"


def insert_contribution(kind: str, filename: str, label: Optional[str], metadata: Dict[str, Any], path: str) -> str:
    contribution_id = str(uuid.uuid4())
    with db_lock, sqlite3.connect(DB_PATH) as conn:
        conn.execute(
            """
            INSERT INTO contributions (id, created_at, kind, filename, label, metadata, path)
            VALUES (?, ?, ?, ?, ?, ?, ?)
            """,
            (contribution_id, now_iso(), kind, filename, label, json.dumps(metadata), path),
        )
        conn.commit()
    return contribution_id


def insert_training_run(run_id: str, status: str, metrics: Optional[Dict[str, Any]] = None, model_path: Optional[str] = None, error: Optional[str] = None, finished_at: Optional[str] = None) -> None:
    with db_lock, sqlite3.connect(DB_PATH) as conn:
        conn.execute(
            """
            INSERT OR REPLACE INTO training_runs (id, started_at, finished_at, status, metrics, model_path, error)
            VALUES (
                ?,
                COALESCE((SELECT started_at FROM training_runs WHERE id = ?), ?),
                ?,
                ?,
                ?,
                ?,
                ?
            )
            """,
            (
                run_id,
                run_id,
                now_iso(),
                finished_at,
                status,
                json.dumps(metrics) if metrics is not None else None,
                model_path,
                error,
            ),
        )
        conn.commit()


def update_training_run(run_id: str, status: str, metrics: Optional[Dict[str, Any]] = None, model_path: Optional[str] = None, error: Optional[str] = None) -> None:
    with db_lock, sqlite3.connect(DB_PATH) as conn:
        conn.execute(
            """
            UPDATE training_runs
            SET finished_at = ?, status = ?, metrics = ?, model_path = ?, error = ?
            WHERE id = ?
            """,
            (now_iso(), status, json.dumps(metrics) if metrics is not None else None, model_path, error, run_id),
        )
        conn.commit()


def load_contributions() -> Tuple[List[str], List[str]]:
    image_paths = []
    labels = []
    with db_lock, sqlite3.connect(DB_PATH) as conn:
        rows = conn.execute(
            "SELECT path, label FROM contributions WHERE kind = 'image' AND label IS NOT NULL AND label != ''"
        ).fetchall()
    for path, label in rows:
        if os.path.exists(path):
            image_paths.append(path)
            labels.append(label)
    return image_paths, labels


def load_csv_dataset(csv_path: str) -> Tuple[np.ndarray, np.ndarray]:
    df = pd.read_csv(csv_path)
    if df.shape[1] < 2:
        raise ValueError("CSV must contain at least one feature column and one label column.")
    label_col = df.columns[-1]
    feature_df = df.iloc[:, :-1]
    labels = df[label_col].astype(str).values
    features = feature_df.values.astype(np.float32)
    return features, labels


def build_image_model(num_classes: int) -> tf.keras.Model:
    base = tf.keras.applications.MobileNetV2(
        input_shape=(IMAGE_SIZE[0], IMAGE_SIZE[1], 3),
        include_top=False,
        weights="imagenet",
    )
    base.trainable = False
    inputs = tf.keras.Input(shape=(IMAGE_SIZE[0], IMAGE_SIZE[1], 3))
    x = tf.keras.applications.mobilenet_v2.preprocess_input(inputs)
    x = base(x, training=False)
    x = tf.keras.layers.GlobalAveragePooling2D()(x)
    x = tf.keras.layers.Dropout(0.2)(x)
    outputs = tf.keras.layers.Dense(num_classes, activation="softmax")(x)
    model = tf.keras.Model(inputs, outputs)
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=1e-3),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    return model


def prepare_image_dataset(image_paths: List[str], labels: List[str]) -> Tuple[tf.data.Dataset, tf.data.Dataset, Dict[str, int]]:
    if not image_paths:
        raise ValueError("No labeled image contributions available for training.")
    class_names = sorted(set(labels))
    class_to_idx = {name: idx for idx, name in enumerate(class_names)}
    y = np.array([class_to_idx[label] for label in labels], dtype=np.int32)

    def load_and_preprocess(path: tf.Tensor, label: tf.Tensor) -> Tuple[tf.Tensor, tf.Tensor]:
        img = tf.io.read_file(path)
        img = tf.image.decode_image(img, channels=3, expand_animations=False)
        img = tf.image.resize(img, IMAGE_SIZE)
        img = tf.cast(img, tf.float32)
        return img, label

    paths_tensor = tf.constant(image_paths)
    labels_tensor = tf.constant(y)
    ds = tf.data.Dataset.from_tensor_slices((paths_tensor, labels_tensor))
    ds = ds.shuffle(buffer_size=len(image_paths), seed=SEED, reshuffle_each_iteration=True)
    ds = ds.map(load_and_preprocess, num_parallel_calls=tf.data.AUTOTUNE)

    val_size = max(1, int(len(image_paths) * VALIDATION_SPLIT))
    train_size = max(1, len(image_paths) - val_size)
    train_ds = ds.take(train_size).batch(BATCH_SIZE).prefetch(tf.data.AUTOTUNE)
    val_ds = ds.skip(train_size).batch(BATCH_SIZE).prefetch(tf.data.AUTOTUNE)
    return train_ds, val_ds, class_to_idx


def train_image_model(run_id: str) -> None:
    with train_lock:
        training_status["running"] = True
        training_status["last_error"] = None
        training_status["last_started"] = now_iso()
        training_status["last_finished"] = None
        training_status["last_metrics"] = None
        training_status["last_model_path"] = None

        try:
            image_paths, labels = load_contributions()
            if len(image_paths) < 2:
                raise ValueError("Need at least 2 labeled image contributions to train.")

            train_ds, val_ds, class_to_idx = prepare_image_dataset(image_paths, labels)
            model = build_image_model(num_classes=len(class_to_idx))

            callbacks = [
                tf.keras.callbacks.EarlyStopping(monitor="val_accuracy", patience=2, restore_best_weights=True),
                tf.keras.callbacks.ModelCheckpoint(
                    filepath=os.path.join(MODEL_DIR, "best_model.keras"),
                    monitor="val_accuracy",
                    save_best_only=True,
                    save_weights_only=False,
                ),
            ]

            history = model.fit(train_ds, validation_data=val_ds, epochs=EPOCHS, callbacks=callbacks, verbose=0)
            metrics = {
                "train_accuracy": float(history.history["accuracy"][-1]) if "accuracy" in history.history else None,
                "val_accuracy": float(history.history["val_accuracy"][-1]) if "val_accuracy" in history.history else None,
                "train_loss": float(history.history["loss"][-1]) if "loss" in history.history else None,
                "val_loss": float(history.history["val_loss"][-1]) if "val_loss" in history.history else None,
                "num_samples": len(image_paths),
                "num_classes": len(class_to_idx),
                "class_mapping": class_to_idx,
            }

            model_path = os.path.join(MODEL_DIR, f"model_{run_id}.keras")
            model.save(model_path)

            training_status["last_metrics"] = metrics
            training_status["last_model_path"] = model_path
            training_status["last_finished"] = now_iso()
            update_training_run(run_id, status="completed", metrics=metrics, model_path=model_path)
        except Exception as e:
            training_status["last_error"] = str(e)
            training_status["last_finished"] = now_iso()
            update_training_run(run_id, status="failed", error=str(e))
        finally:
            training_status["running"] = False


