@app.post("/contribute/image", response_model=ContributionResponse)
async def contribute_image(
    file: UploadFile = File(...),
    label: str = Form(...),
    metadata: Optional[str] = Form(None),
) -> ContributionResponse:
    if not allowed_image_filename(file.filename):
        raise HTTPException(status_code=400, detail="Unsupported image file type.")
    if not label.strip():
        raise HTTPException(status_code=400, detail="Label is required.")

    contribution_id = str(uuid.uuid4())
    ext = os.path.splitext(file.filename)[1].lower()
    stored_name = f"{contribution_id}{ext}"
    stored_path = os.path.join(UPLOAD_DIR, stored_name)
    save_upload_file(file, stored_path)

    meta = {}
    if metadata:
        try:
            meta = json.loads(metadata)
        except json.JSONDecodeError:
            meta = {"raw_metadata": metadata}

    insert_contribution("image", file.filename, label.strip(), meta, stored_path)
    return ContributionResponse(status="ok", message="Image contribution accepted.", contribution_id=contribution_id)


