@app.post("/train/csv")
async def train_from_csv(file: UploadFile = File(...)) -> Dict[str, Any]:
    if not allowed_csv_filename(file.filename):
        raise HTTPException(status_code=400, detail="Only CSV files are supported.")
    content = await file.read()
    temp_path = os.path.join(DATA_DIR, f"{uuid.uuid4()}.csv")
    with open(temp_path, "wb") as f:
        f.write(content)

    try:
        features, labels = load_csv_dataset(temp_path)
        classes = sorted(set(labels.tolist()))
        class_to_idx = {c: i for i, c in enumerate(classes)}
        y = np.array([class_to_idx[l] for l in labels], dtype=np.int32)

        model = tf.keras.Sequential(
            [
                tf.keras.layers.Input(shape=(features.shape[1],)),
                tf.keras.layers.Dense(128, activation="relu"),
                tf.keras.layers.Dropout(0.2),
                tf.keras.layers.Dense(64, activation="relu"),
                tf.keras.layers.Dense(len(classes), activation="softmax"),
            ]
        )
        model.compile(
            optimizer="adam",
            loss="sparse_categorical_crossentropy",
            metrics=["accuracy"],
        )

        history = model.fit(
            features,
            y,
            validation_split=0.2 if len(features) > 5 else 0.0,
            epochs=EPOCHS,
            batch_size=BATCH_SIZE,
            verbose=0,
        )

        model_path = os.path.join(MODEL_DIR, f"csv_model_{uuid.uuid4()}.keras")
        model.save(model_path)

        metrics = {
            "accuracy": float(history.history["accuracy"][-1]) if "accuracy" in history.history else None,
            "loss": float(history.history["loss"][-1]) if "loss" in history.history else None,
            "num_samples": int(features.shape[0]),
            "num_features": int(features.shape[1]),
            "num_classes": int(len(classes)),
            "class_mapping": class_to_idx,
        }
        return {"status": "ok", "message": "CSV model trained.", "model_path": model_path, "metrics": metrics}
    finally:
        if os.path.exists(temp_path):
            os.remove(temp_path)


@app.exception_handler(Exception)
async def generic_exception_handler(_, exc: Exception):
    return JSONResponse(status_code=500, content={"status": "error", "detail": str(exc)})


